// Assuming msg.payload is an array of stock data
// Each item: { symbol, price, volume, rsi, macd, bb_upper, bb_lower, up_days, down_days, price_change }

var stocks = msg.payload;
var totalStocks = stocks.length;

var strongWeakRatio = 0;
var techIndicators = 0;
var fundFlow = 0;

stocks.forEach(function(stock) {
    // 成份股強弱比例: (up_days / (up_days + down_days)) averaged
    if (stock.up_days + stock.down_days > 0) {
        strongWeakRatio += stock.up_days / (stock.up_days + stock.down_days);
    }

    // 技術指標: average of normalized RSI (0-100), MACD signal, BB position
    var rsiNorm = stock.rsi / 100;
    var macdNorm = stock.macd > 0 ? 1 : 0; // simplified
    var bbNorm = (stock.price - stock.bb_lower) / (stock.bb_upper - stock.bb_lower); // position in band
    techIndicators += (rsiNorm + macdNorm + bbNorm) / 3;

    // 資金流指標: volume change and price change normalized
    fundFlow += (stock.volume_change / stock.avg_volume) + (stock.price_change / stock.price);
});

strongWeakRatio /= totalStocks;
techIndicators /= totalStocks;
fundFlow /= totalStocks;

// Normalize to 0-1 scale
techIndicators /= 3; // since averaged 3 indicators
fundFlow /= 2; // volume and price

// Final Score: 30% strongWeak + 40% tech + 30% fundFlow
var referenceScore = (strongWeakRatio * 0.3) + (techIndicators * 0.4) + (fundFlow * 0.3);

msg.payload = {
    date: new Date(),
    reference_score: referenceScore,
    components: {
        strong_weak_ratio: strongWeakRatio,
        tech_indicators: techIndicators,
        fund_flow: fundFlow
    }
};

return msg;
